package qa.operator;

public class Relational_operator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int a,b;
		a=6;
		b=5;
		
		System.out.println(a==b);
		System.out.println(a!=b);
		System.out.println(a>b);
		System.out.println(a<b);
		System.out.println(a>=b);
		System.out.println(a<=b);

	}

}
